Let's try a different approach. Instead of configuring it in the formatter settings, we can conditionally include prettierd in the `formatters_by_ft` based on the presence of a config file:

```lua
return {
  { -- Autoformat
    'stevearc/conform.nvim',
    event = { 'BufWritePre' },
    cmd = { 'ConformInfo' },
    keys = {
      {
        '<leader>f',
        function()
          require('conform').format { async = true, lsp_format = 'fallback' }
        end,
        mode = '',
        desc = '[F]ormat buffer',
      },
    },
    opts = function()
      local prettier_files = {
        ".prettierrc",
        ".prettierrc.json",
        ".prettierrc.yml",
        ".prettierrc.yaml",
        ".prettierrc.json5",
        ".prettierrc.js",
        ".prettierrc.cjs",
        "prettier.config.js",
        "prettier.config.cjs",
      }

      local function get_formatters(ft)
        local found = vim.fs.find(function(name)
          return vim.tbl_contains(prettier_files, name)
        end, { upward = true, type = 'file' })

        return #found > 0 and { 'prettierd' } or {}
      end

      return {
        notify_on_error = true,
        format_on_save = function(bufnr)
          local disable_filetypes = { c = true, cpp = true }
          local lsp_format_opt
          if disable_filetypes[vim.bo[bufnr].filetype] then
            lsp_format_opt = 'never'
          else
            lsp_format_opt = 'fallback'
          end
          return {
            timeout_ms = 500,
            lsp_format = lsp_format_opt,
          }
        end,
        formatters_by_ft = {
          lua = { 'stylua' },
          javascript = get_formatters,
          typescript = get_formatters,
          javascriptreact = get_formatters,
          typescriptreact = get_formatters,
          html = get_formatters,
          css = get_formatters,
          json = get_formatters,
        },
      }
    end,
  },
}
