        html = { 'prettierd' },
        css = { 'prettierd' },
        json = { 'prettierd' },
      },
      formatters = {
        prettierd = {
          condition = function(ctx)
            -- Get the root directory from LSP if available
            local root_dir
            local clients = vim.lsp.get_active_clients({ bufnr = ctx.buf })
            for _, client in ipairs(clients) do
              if client.config.root_dir then
                root_dir = client.config.root_dir
                break
              end
            end

            -- Fall back to the current file's directory if no LSP root is found
            root_dir = root_dir or ctx.dirname

            -- List of Prettier config files to check for
            local config_files = {
              ".prettierrc",
              ".prettierrc.json",
              ".prettierrc.yml",
              ".prettierrc.yaml",
              ".prettierrc.json5",
              ".prettierrc.js",
              ".prettierrc.cjs",
              ".prettierrc.mjs",
              ".prettierrc.toml",
              "prettier.config.js",
              "prettier.config.cjs",
              "prettier.config.mjs",
              "package.json",
            }

            -- Check for config files
            for _, file in ipairs(config_files) do
              if vim.uv.fs_stat(vim.fs.joinpath(root_dir, file)) then
                ctx.cwd = root_dir -- Set the working directory for prettierd
                return true
              end
            end
            return false
          end,
        },
      },
    },
  },
}
